<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initiallag=1.0">
    <title>Ubuntu Desktop Clone</title>
    <style>
        :root {
            --ubuntu-orange: #e95420;
            --ubuntu-purple: #3d5a80;
            --ubuntu-dark: #2c001e;
            --window-bg: #300a24;
            --taskbar-bg: rgba(0, 0, 0, 0.6);
            --text-color: #ffffff;
            --header-bg: #4e6781;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body, html {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-family: 'Ubuntu', sans-serif, Arial;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #2c001e 0%, #3d5a80 100%);
            position: relative;
            overflow: hidden;
        }

        #taskbar {
            position: absolute;
            bottom: 15px;
            left: 50%;
            transform: translateX(-50%);
            background: var(--taskbar-bg);
            padding: 8px 20px;
            border-radius: 30px;
            display: flex;
            gap: 15px;
            backdrop-filter: blur(10px);
            z-index: 1000;
            border: 1px solid rgba(255,255,255,0.1);
        }

        .launcher-btn {
            background: none;
            border: none;
            color: white;
            font-size: 24px;
            cursor: pointer;
            padding: 5px 10px;
            transition: transform 0.2s, background 0.2s;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .launcher-btn:hover {
            background: rgba(255, 255, 255, 0.2);
            transform: scale(1.1);
            border-radius: 50%;
        }

        /* Window Styles */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            color: white;
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none;
            flex-direction: column;
            overflow: hidden;
            z-index: 10;
        }

        .win-header {
            background: var(--header-bg);
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            user-select: none;
        }

        .win-title {
            font-size: 14px;
            font-weight: bold;
        }

        .win-controls {
            display: flex;
            gap: 8px;
        }

        .win-close {
            background: #e95420;
            border: none;
            width: 14px;
            height: 14px;
            border-radius: 50%;
            cursor: pointer;
        }

        .win-content {
            flex: 1;
            padding: 15px;
            overflow: auto;
            position: relative;
        }

        /* Files App Styles */
        #files-path {
            font-family: monospace;
            background: rgba(0,0,0,0.3);
            padding: 4px 8px;
            border-radius: 4px;
            margin-bottom: 10px;
            display: block;
            word-break: break-all;
        }

        #files-up {
            cursor: pointer;
            color: var(--ubuntu-orange);
            font-weight: bold;
            margin-bottom: 10px;
            display: inline-block;
        }

        .fs-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            text-align: center;
            cursor: pointer;
            padding: 5px;
            border-radius: 4px;
            font-size: 12px;
        }

        .fs-item:hover {
            background: rgba(255,255,255,0.1);
        }

        .fs-icon {
            width: 32px;
            height: 32px;
            margin-bottom: 5px;
            background: #666;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        /* Notepad Styles */
        #tabs {
            display: flex;
            gap: 2px;
            background: rgba(0,0,0,0.2);
            padding: 5px 5px 0 5px;
        }

        .tab {
            padding: 6px 12px;
            background: #444;
            color: #ccc;
            border-radius: 5px 5px 0 0;
            cursor: pointer;
            font-size: 13px;
            white-space: nowrap;
        }

        .tab.active {
            background: var(--window-bg);
            color: white;
        }

        #new-tab {
            padding: 2px 8px;
            cursor: pointer;
            background: none;
            border: none;
            color: white;
            font-size: 18px;
        }

        #editor {
            width: 100%;
            height: 100%;
            min-height: 200px;
            background: transparent;
            border: none;
            color: white;
            resize: none;
            outline: none;
            font-family: monospace;
            padding: 5px;
        }

        .notepad-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }
    </wrap>
    </style>
</head>
