                    { name: 'Downloads', type: 'dir', children: [] },
                    { name: 'Pictures', type: 'dir', children: [] }
                ]}
            ]},
            { name: 'usr', type: 'dir', children: [] },
            { name: 'var', type: 'dir', children: [] }
        ]
    };

    let currentDir = fsTree;
    const pathDisplay = document.getElementById('files-path');
