    let dirStack = [fsTree];

    function renderFiles() {
        const dir = dirStack[dirStack.length - 1];

        // Update Path Text
        let pathStr = "";
        for(let i=0; i<dirStack.length; i++) {
            if (dirStack[i].name === '/') pathStr += "/";
            else pathStr += "/" + dirStack[i].name;
        }
        pathDisplay.innerText = pathStr === "" ? "/" : pathStr.replace('//', '/');

        // Update Up Button
        filesUpBtn.style.display = dirStack.length > 1 ? 'block' : 'none';
        filesUpBtn.onclick = () => {
            dirStack.pop();
            renderFiles();
        };

        fsContainer.innerHTML = '';
        dir.children.forEach(child => {
            const item = document.createElement('div');
            item.className = 'fs-item';

            const icon = document.createElement('div');
            icon.className = 'fs-icon';
            icon.innerText = child.type === 'dir' ? '📁' : '📄';

            const label = document.createElement('span');
            label.innerText = child.name;

            item.appendChild(icon);
            item.appendChild(label);

            item.ondblclick = () => {
                if (child.type === 'dir') {
                    dirStack.push(child);
                    renderFiles();
                }
            };
            fsContainer.appendChild(item);
        });
    }

    /** 
     * NOTEPAD LOGIC
     */
    let tabs = [];
    let activeTabId = null;
    const tabStrip = document.getElementById('tabs');
    const editor = document.topElement || document.getElementById('editor'); // fallback
    const editorEl = document.getElementById('editor');
    const newTabBtn = document.getElementById('new-tab');

    function loadNotepad() {
        const saved = localStorage.getItem('ubuntu_notepad');
        if (saved) {
            const data = JSON.parse(saved);
            tabs = data.tabs;
            activeTabId = data.activeTabId;
        } else {
            const initialId = Date.now();
            tabs = [{ id: initialId, title: 'Untitled', content: '' }];
            activeTabId = initialId;
        }
        renderTabs();
    }

    function saveNotepad() {
        localStorage.setItem('ubuntu_notepad', JSON.stringify({
            tabs: tabs,
            activeTabId: activeTabId
        }));
    }

    function renderTabs() {
        // Clear existing tabs (keep the + button)
        const buttons = tabStrip.querySelectorAll('.tab');
        buttons.forEach(b => b.remove());

        tabs.forEach(tab => {
            const t = document.createElement('div');
            t.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
            t.innerText = tab.title;
            t.onclick = () => switchTab(tab.id);
            tabStrip.insertBefore(t, newTabBtn);
        });

        const activeTab = tabs.find(t => t.id === activeTabId);
        editorEl.value = activeTab ? activeTab.content : '';
    }

    function switchTab(id) {
        activeTabId = id;
        renderTabs();
        saveNotepad();
    }

